// Loop over input items and add a new field called 'myNewField' to the JSON of each one
const items = $input.all();
const headlines = items.map(item => {
  return `TITLE: ${item.json.title}\nSUMMARY: ${item.json.contentSnippet || item.json.description}\nLINK: ${item.json.link}`;
}).join('\n\n---\n\n');

return [{ json: { bundled_news: headlines } }];
